function fmtVnd(n){const v=Number(n);if(!Number.isFinite(v))return"—";try{return new Intl.NumberFormat("vi-VN").format(Math.round(v))+" ₫";}catch{return String(Math.round(v))+" ₫";}}
function linesToArr(text){return String(text||"").split("\n").map((s)=>s.trim()).filter(Boolean);}
function arrToLines(arr){return(arr||[]).join("\n");}
function parseJsonField(text,fallback){const raw=String(text||"").trim();if(!raw)return fallback;try{const v=JSON.parse(raw);return v??fallback;}catch{throw new Error("JSON không hợp lệ.");}}
