if(!assertStepAccessible(tab))return;const meta=SECTION_META[tab];if(!meta)return;activeSectionTab=tab;const icoEl=document.getElementById("crm-re-section-ico");const kickerEl=document.getElementById("crm-re-section-kicker");const titleEl=document.getElementById("crm-re-section-title");const subEl=document.getElementById("crm-re-section-sub");const projectName=activeProject?.name||"";if(icoEl){icoEl.textContent=meta.ico;icoEl.className=`crm-re-form-head-ico crm-re-form-head-ico--${meta.tone}`;}
if(kickerEl)kickerEl.textContent=meta.kicker;if(titleEl)titleEl.textContent=meta.title;if(subEl)subEl.textContent=projectName?`Dự án: ${projectName}`:"";document.querySelectorAll("[data-re-section-pane]").forEach((pane)=>{pane.hidden=pane.getAttribute("data-re-section-pane")!==tab;});const root=document.getElementById("crm-re-section-modal");if(root){root.removeAttribute("hidden");root.classList.add("is-open");root.setAttribute("aria-hidden","false");document.body.style.overflow="hidden";}
