function navigateWorkflowStep(delta){const current=activeSectionTab||"overview";const idx=workflowStepIndex(current);const next=WORKFLOW_STEPS[idx+delta];if(!next)return;switchTab(next.id);}
function exportUrl(report,format){if(!activeProjectId)return"";const q=new URLSearchParams({report,format});return`/api/crm/re-projects/${activeProjectId}/export?${q.toString()}`;}
