async function loadOverviewZones(){const el=document.getElementById("crm-re-overview-zones");if(!el||!activeProjectId)return;try{const data=await reqJson(`/api/crm/re-projects/${activeProjectId}/inventory-by-zone`);renderOverviewZones(data.zones||[]);}catch(err){el.innerHTML=`<p class="muted">${esc(err.message || "Không tải tồn kho theo phân khu.")}</p>`;}}
function stopOverviewPoll(){if(overviewPollTimer){window.clearInterval(overviewPollTimer);overviewPollTimer=0;}}
function startOverviewPoll(){stopOverviewPoll();overviewPollTimer=window.setInterval(()=>{const pane=document.querySelector('[data-re-pane="overview"]');if(!activeProjectId||!pane||pane.hidden)return;loadOverviewZones().catch(()=>{});loadSummary().catch(()=>{});},OVERVIEW_POLL_MS);}
